## 3.  OCaml C‑C++ stubs – `pcapng_stubs.cpp`

```cpp
/* --------------------------------------------------------------
   pcapng_stubs.cpp – OCaml <-> libpcapng binding
   -------------------------------------------------------------- */

#define CAML_NAME_SPACE          // avoid name clashes
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/callback.h>
#include <caml/fail.h>
#include <caml/bigarray.h>

#include "pcapng_wrapper.hpp"
#include <cstring>   // memcpy
#include <exception>

/* --------------------------------------------------------------
   Custom block that holds a `pcapng_handle*`.
   -------------------------------------------------------------- */
static void pcapng_finalize(value v)
{
    pcapng_handle* h = *(pcapng_handle**)Data_custom_val(v);
    delete h;               // unique_ptr destroys the Reader
}

/* The custom operations record – we only need a finaliser. */
static struct custom_operations pcapng_ops = {
    "pcapng.handle",
    pcapng_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default
};

/* --------------------------------------------------------------
   Helper: allocate a custom block and store the pointer.
   -------------------------------------------------------------- */
static value alloc_handle(pcapng_handle* h)
{
    value v = caml_alloc_custom(&pcapng_ops,
                                sizeof(pcapng_handle*),
                                0,   // no extra memory
                                1);  // finaliser runs
    pcapng_handle** p = (pcapng_handle**)Data_custom_val(v);
    *p = h;
    return v;
}

/* --------------------------------------------------------------
   open_file : string -> t
   -------------------------------------------------------------- */
extern "C" CAMLprim value caml_pcapng_open_file(value v_path)
{
    CAMLparam1(v_path);
    CAMLlocal1(v_handle);

    const char* path = String_val(v_path);
    try {
        pcapng_handle* h = new pcapng_handle(std::string(path));
        v_handle = alloc_handle(h);
    } catch (const std::exception& e) {
        caml_failwith(e.what());
    }

    CAMLreturn(v_handle);
}

/* --------------------------------------------------------------
   close : t -> unit
   -------------------------------------------------------------- */
extern "C" CAMLprim value caml_pcapng_close(value v_handle)
{
    CAMLparam1(v_handle);
    /* The finaliser will delete the handle; we just clear the pointer
       so that a second call to close becomes a no‑op. */
    pcapng_handle** ph = (pcapng_handle**)Data_custom_val(v_handle);
    if (*ph != nullptr) {
        delete *ph;
        *ph = nullptr;
    }
    CAMLreturn(Val_unit);
}

/* --------------------------------------------------------------
   iter_frames : t -> (frame -> unit) -> unit
   -------------------------------------------------------------- */
extern "C" CAMLprim value caml_pcapng_iter_frames(value v_handle,
                                                 value v_cb)
{
    CAMLparam2(v_handle, v_cb);
    CAMLlocal1(v_frame);        // used for each iteration

    /* -----------------------------------------------------------------
       Retrieve the C++ Reader object.
       ----------------------------------------------------------------- */
    pcapng_handle* h = *(pcapng_handle**)Data_custom_val(v_handle);
    if (h == nullptr) caml_failwith("Pcapng.handle is closed");

    /* -----------------------------------------------------------------
       Iterate in the C++ world *without* holding the OCaml runtime lock.
       The lock is reacquired only when we need to call back into OCaml.
       ----------------------------------------------------------------- */
    caml_release_runtime_system();
    try {
        for (auto it = h->reader->begin(); it != h->reader->end(); ++it) {
            const libpcapng::Frame& f = *it;

            /* ---------------------------------------------------------
               Re‑acquire the runtime before we build any OCaml value.
               --------------------------------------------------------- */
            caml_acquire_runtime_system();

            /* Build the OCaml `frame` record (5 fields). */
            v_frame = caml_alloc(5, 0);   // tag 0 = record
            Store_field(v_frame, 0, Val_int(static_cast<int>(f.ts_sec)));
            Store_field(v_frame, 1, Val_int(static_cast<int>(f.ts_usec)));
            Store_field(v_frame, 2, Val_int(static_cast<int>(f.caplen)));
            Store_field(v_frame, 3, Val_int(static_cast<int>(f.origlen)));

            /* The payload – a fresh `bytes` value. */
            value v_data = caml_alloc_string(static_cast<std::size_t>(f.caplen));
            if (f.caplen > 0)
                std::memcpy(String_val(v_data), f.data.data(),
                            static_cast<std::size_t>(f.caplen));
            Store_field(v_frame, 4, v_data);

            /* ---------------------------------------------------------
               Call the user supplied OCaml callback.  If it raises, we
               propagate the exception after cleaning up.
               --------------------------------------------------------- */
            caml_callback(v_cb, v_frame);

            /* ---------------------------------------------------------
               Release the lock again before the next iteration.
               --------------------------------------------------------- */
            caml_release_runtime_system();
        }
    } catch (const std::exception& e) {
        caml_acquire_runtime_system();   // make sure we have the lock
        caml_failwith(e.what());
    }

    CAMLreturn(Val_unit);
}

/* --------------------------------------------------------------
   Register the functions for the OCaml side.
   -------------------------------------------------------------- */
extern "C" CAMLprim value caml_pcapng_stub_init(value unit)
{
    CAMLparam1(unit);
    /* No side‑effects; the mere existence of the symbols is enough.
       The function is exported so that the OCaml compiler/linker can
       force the object file to be linked. */
    CAMLreturn(Val_unit);
}
```

### 3.1  What the stub does (step‑by‑step)

| OCaml call | C stub action |
|------------|---------------|
| `open_file` | *creates* a `pcapng_handle` (which owns a `libpcapng::Reader`), stores the pointer in a custom block, and returns it. |
| `close` | *Deletes* the C++ object (if not already deleted) and clears the pointer – the finaliser will become a no‑op. |
| `iter_frames` | *Releases* the OCaml runtime lock, walks the C++ iterator, and for each frame: <br>· *re‑acquires* the lock <br>· builds an OCaml `frame` record (copies timestamp, lengths and packet bytes) <br>· calls the user callback via `caml_callback` <br>· *releases* the lock again before the next iteration. <br>If the callback raises, the exception propagates back to OCaml. |

