## 4.  Build instructions

Below is a **minimal `dune` stanza** (the modern OCaml build system).  
If you prefer a classic `Makefile`, see the comment after the stanza.

```
(executable
 (name demo)                     ; optional test program
 (modules demo)                  ; your demo .ml file
 (libraries pcapng))            ; links against the library we are building

(library
 (name pcapng)
 (public_name pcapng)            ; OCaml name for `open Pcapng`
 (foreign_stubs
  (language cxx)                 ; we compile the stubs as C++
  (names pcapng_stubs)           ; -> pcapng_stubs.cpp
  (flags (:standard -Wall -O2))
  (include_dirs .)))             ; where pcapng_wrapper.hpp lives

;; You must also tell the linker where libpcapng lives:
(env
 (link_flags (:standard -lpcapng)))   ; <-- replace with the real lib name
```

### Classic `Makefile` alternative

```make
OCAMLFLAGS = -thread -g
CXXFLAGS   = -Wall -O2 -I. -std=c++17
LIBS       = -lpcapng   # <-- adjust as needed

all: libpcapng_stubs.o libpcapng.a pcapng.cma

libpcapng_stubs.o: pcapng_stubs.cpp pcapng_wrapper.hpp
	$(CXX) $(CXXFLAGS) -c $< -o $@

libpcapng.a: libpcapng_stubs.o
	ar rcs $@ $^

pcapng.cma: pcapng.cmi pcapng.cmo libpcapng.a
	ocamlc -a -o $@ $^

pcapng.cmi pcapng.cmo: pcapng.ml pcapng.mli
	ocamlc $(OCAMLFLAGS) -c pcapng.mli
	ocamlc $(OCAMLFLAGS) -c pcapng.ml

clean:
	rm -f *.o *.a *.cmi *.cmo *.cma
```

Compile with

```sh
make
# or, with dune:
dune build
```

